import * as msal from '@azure/msal-browser';

/**
 * Configuración de MSAL para login federado con Microsoft Azure AD.
 * Las variables se leen del .env (VUE_APP_AZURE_CLIENT_ID, VUE_APP_AZURE_TENANT_ID, VUE_APP_AZURE_REDIRECT_URI).
 */
const msalConfig = {
  auth: {
    clientId: process.env.VUE_APP_AZURE_CLIENT_ID || '',
    authority: `https://login.microsoftonline.com/${process.env.VUE_APP_AZURE_TENANT_ID || 'common'}`,
    redirectUri: process.env.VUE_APP_AZURE_REDIRECT_URI || window.location.origin,
    postLogoutRedirectUri: window.location.origin
  },
  cache: {
    cacheLocation: 'localStorage',
    storeAuthStateInCookie: false
  }
};

const loginRequest = {
  scopes: ['User.Read']
};

let msalInstance = null;

/**
 * Retorna la instancia MSAL inicializada (singleton).
 * Se inicializa de forma lazy para evitar errores si las variables de entorno no están configuradas.
 */
export async function getMsalInstance() {
  if (!msalInstance) {
    msalInstance = new msal.PublicClientApplication(msalConfig);
    await msalInstance.initialize();
  }
  return msalInstance;
}

/**
 * Abre el popup de login de Microsoft y retorna el access token.
 * @returns {Promise<string>} access token de Microsoft
 */
export async function loginWithMicrosoft() {
  const instance = await getMsalInstance();
  const response = await instance.loginPopup(loginRequest);
  return response.accessToken;
}

/**
 * Cierra la sesión de Microsoft.
 */
export async function logoutMicrosoft() {
  try {
    const instance = await getMsalInstance();
    await instance.logoutPopup();
  } catch (e) {
    // Silenciar errores de logout
    console.debug('MSAL logout:', e);
  }
}

export { loginRequest };
